headerButton.customFunction:
// ThingsBoard PE - Bulk Update Inactivity Timeout
// Para: Header action button en tabla de dispositivos
// Aplica un inactivityTimeout a TODOS los dispositivos del customer o tenant

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get("customDialog"));
let attributeService = $injector.get(
  widgetContext.servicesMap.get("attributeService"),
);

openBulkTimeoutDialog();

function openBulkTimeoutDialog() {
  customDialog.customDialog(htmlTemplate, BulkTimeoutController).subscribe();
}

function BulkTimeoutController(instance) {
  let vm = instance;

  // Estado
  vm.loading = true;
  vm.saving = false;
  vm.devices = [];
  vm.deviceCount = 0;

  // Progreso
  vm.progress = 0;
  vm.processed = 0;
  vm.errors = 0;
  vm.conflictingDevices = [];

  // Formulario
  vm.bulkFormGroup = vm.fb.group({
    reportInterval: [null],
    inactivityTimeout: [null],
  });

  // Al cambiar el intervalo de reporte, verifica los timeouts existentes de todos los dispositivos
  vm.bulkFormGroup.get("reportInterval").valueChanges.subscribe(function (val) {
    if (val == null || val === "") {
      vm.conflictingDevices = [];
      return;
    }
    let intervalMin = parseInt(val);
    vm.conflictingDevices = vm.devices
      .filter(function (d) {
        let timeoutVal = d.latest && d.latest["ATTRIBUTE"] && d.latest["ATTRIBUTE"]["inactivityTimeout"]
          ? d.latest["ATTRIBUTE"]["inactivityTimeout"].value
          : null;
        if (timeoutVal == null) return false;
        return Math.round(timeoutVal / 60000) <= intervalMin;
      })
      .map(function (d) {
        let name = (d.latest && d.latest["ENTITY_FIELD"] && d.latest["ENTITY_FIELD"]["name"])
          ? d.latest["ENTITY_FIELD"]["name"].value
          : d.entityId.id;
        let timeoutVal = d.latest["ATTRIBUTE"]["inactivityTimeout"].value;
        return { name: name, timeoutMinutes: Math.round(timeoutVal / 60000) };
      });
  });

  // Al cambiar el timeout, valida que sea mayor al intervalo de reporte
  vm.bulkFormGroup.get("inactivityTimeout").valueChanges.subscribe(function (val) {
    let interval = vm.bulkFormGroup.get("reportInterval").value;
    let timeoutCtrl = vm.bulkFormGroup.get("inactivityTimeout");
    if (val != null && interval != null && val !== "" && interval !== "") {
      if (parseInt(val) <= parseInt(interval)) {
        timeoutCtrl.setErrors({ inactivityTooLow: true });
      } else {
        timeoutCtrl.setErrors(null);
      }
    }
  });

  // Inicializar: cargar todos los devices via Entity Query API
  loadAllDevices();

  vm.cancel = function () {
    vm.dialogRef.close(null);
  };

  vm.save = function () {
    let formValue = vm.bulkFormGroup.value;
    let timeoutMinutes = formValue.inactivityTimeout;
    let reportIntervalVal = formValue.reportInterval;

    let hasTimeout = timeoutMinutes != null && timeoutMinutes !== "" && timeoutMinutes > 0;
    let hasInterval = reportIntervalVal != null && reportIntervalVal !== "" && reportIntervalVal > 0;

    if (!hasTimeout && !hasInterval) {
      widgetContext.showErrorToast("Ingresá al menos un valor para actualizar");
      return;
    }

    if (vm.conflictingDevices.length > 0) {
      widgetContext.showErrorToast("Hay dispositivos con timeout conflictivo");
      return;
    }

    vm.bulkFormGroup.markAsPristine();
    vm.saving = true;
    vm.processed = 0;
    vm.errors = 0;

    let timeoutMs = hasTimeout ? Math.round(timeoutMinutes * 60 * 1000) : null;
    let reportIntervalInt = hasInterval ? parseInt(reportIntervalVal) : null;

    let completed = 0;
    let errorCount = 0;

    vm.devices.forEach(function (device) {
      let entityId = { id: device.entityId.id, entityType: "DEVICE" };

      function deviceDone(success) {
        completed++;
        if (!success) errorCount++;
        vm.processed = completed;
        vm.errors = errorCount;
        vm.progress = Math.round((completed / vm.devices.length) * 100);
        checkDone();
      }

      function saveShared() {
        if (reportIntervalInt != null) {
          attributeService
            .saveEntityAttributes(entityId, "SHARED_SCOPE", [
              { key: "report_interval", value: reportIntervalInt },
            ])
            .subscribe(
              function () { deviceDone(true); },
              function (error) {
                console.error("Error actualizando " + device.entityId.id + ":", error);
                deviceDone(false);
              },
            );
        } else {
          deviceDone(true);
        }
      }

      if (timeoutMs != null) {
        attributeService
          .saveEntityAttributes(entityId, "SERVER_SCOPE", [
            { key: "inactivityTimeout", value: timeoutMs },
          ])
          .subscribe(
            function () { saveShared(); },
            function (error) {
              console.error("Error actualizando " + device.entityId.id + ":", error);
              deviceDone(false);
            },
          );
      } else {
        saveShared();
      }
    });

    function checkDone() {
      if (completed === vm.devices.length) {
        vm.saving = false;
        if (errorCount === 0) {
          widgetContext.showSuccessToast(
            vm.devices.length + " dispositivos actualizados",
          );
        } else {
          widgetContext.showErrorToast(
            errorCount + " errores de " + vm.devices.length + " dispositivos",
          );
        }
        widgetContext.updateAliases();
        vm.dialogRef.close(true);
      }
    }
  };

  // ─── Cargar TODOS los devices con Entity Query API ───
  // Funciona igual para TENANT_ADMIN y CUSTOMER_USER
  function loadAllDevices() {
    vm.devices = [];
    fetchPage(0);
  }

  function fetchPage(page) {
    let query = {
      entityFilter: {
        type: "entityType",
        entityType: "DEVICE",
      },
      pageLink: {
        pageSize: 100,
        page: page,
        sortOrder: {
          key: { key: "name", type: "ENTITY_FIELD" },
          direction: "ASC",
        },
      },
      entityFields: [
        { type: "ENTITY_FIELD", key: "name" },
        { type: "ENTITY_FIELD", key: "label" },
      ],
      latestValues: [
        { type: "ATTRIBUTE", key: "inactivityTimeout" },
      ],
    };

    widgetContext.http.post("/api/entitiesQuery/find", query).subscribe(
      function (response) {
        let pageData = response.data || [];
        vm.devices = vm.devices.concat(pageData);
        vm.deviceCount = vm.devices.length;

        if (response.hasNext) {
          fetchPage(page + 1);
        } else {
          vm.loading = false;
        }
      },
      function (error) {
        vm.loading = false;
        widgetContext.showErrorToast("Error cargando dispositivos");
        console.error("Error cargando devices:", error);
      },
    );
  }
}

