  font-size: 14px;
  font-weight: 600;
  color: #333;
}

.config-dialog .unsupported-desc {
  margin: 0;
  font-size: 13px;
  color: #777;
  line-height: 1.5;
}

/* ── Diagrama esquemático ── */
.config-dialog .diagram {
  margin: 8px 0 14px;
  padding: 14px 16px 10px;
  background: #ffffff;
  border: 1px solid #ececec;
  border-radius: 6px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
}

.config-dialog .diagram--inline {
  margin: 10px 0 16px;
}

.config-dialog .diagram svg {
  width: 100%;
  max-width: 280px;
  height: auto;
  display: block;
}

.config-dialog .diagram-caption {
  margin: 0;
  font-size: 11.5px;
  color: #666;
  line-height: 1.45;
  text-align: center;
}

.config-dialog .diagram-caption strong {
  color: #EE7623;
  font-weight: 600;
}

.config-dialog .diagram-caption--rule {
  margin-top: 4px;
  padding: 4px 8px;
  background: #fff4ec;
  border-radius: 4px;
  font-size: 11px;
  color: #b8541a;
}

.config-dialog .diagram-caption--rule code {
  font-family: "Roboto Mono", Consolas, monospace;
  font-size: 11px;
  color: #b8541a;
}

/* ── Volume toggle ── */
.config-dialog .volume-toggle-row {
  display: flex;
  align-items: center;
  gap: 14px;
  padding: 14px 0 4px;
  margin-top: 12px;
  border-top: 1px solid #f0f0f0;
}

.config-dialog .volume-toggle-info {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-width: 0;
  gap: 2px;
}

.config-dialog .volume-toggle-label {
  font-size: 14px;
  font-weight: 500;
  color: #333;
}

.config-dialog .volume-toggle-desc {
  font-size: 12px;
  color: #888;
  line-height: 1.4;
}

.config-dialog .volume-toggle.mat-checked .mat-slide-toggle-bar {
  background-color: rgba(238, 118, 35, 0.5) !important;
}

.config-dialog .volume-toggle.mat-checked .mat-slide-toggle-thumb {
  background-color: #ee7623 !important;
}

/* ── Volume config (sub-section) ── */
.config-dialog .volume-config {
  padding-top: 12px;
  margin-top: 6px;
  border-top: 1px dashed #e0e0e0;
}

.config-dialog .volume-config .mat-form-field + .mat-form-field {
  margin-top: 16px;
}

/* ── Capacidad calculada ── */
.config-dialog .capacity-computed {
  margin: 14px 0 10px;
  padding: 10px 14px;
  background: #fff4ec;
  border: 1px solid rgba(238, 118, 35, 0.25);
  border-radius: 6px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.config-dialog .capacity-computed-label {
  font-size: 12px;
  color: #b8541a;
  font-weight: 500;
  letter-spacing: 0.2px;
}

.config-dialog .capacity-computed-value {
  font-size: 15px;
  color: #b8541a;
  font-weight: 700;
  font-family: "Roboto Mono", Consolas, monospace;
}

.config-dialog .capacity-computed--warn {
  background: #fdecea;
  border-color: rgba(244, 67, 54, 0.35);
}

.config-dialog .capacity-computed--warn .capacity-computed-label,
.config-dialog .capacity-computed--warn .capacity-computed-value {
  color: #b71c1c;
}

.config-dialog .capacity-computed-mismatch {
  display: block;
  font-size: 11px;
  font-weight: 400;
  margin-top: 2px;
  font-style: italic;
}

/* ── Strapping ── */
.config-dialog .strapping-header {
  margin-top: 14px;
  margin-bottom: 8px;
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.config-dialog .strapping-title {
  font-size: 13px;
  font-weight: 600;
  color: #333;
}

.config-dialog .strapping-hint {
  font-size: 12px;
  color: #888;
  line-height: 1.4;
}

.config-dialog .strapping-table {
  background: #fafbfc;
  border: 1px solid #e6e8eb;
  border-radius: 6px;
  padding: 8px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.config-dialog .strapping-row {
  display: grid;
  grid-template-columns: 1fr 1fr 40px;
  gap: 8px;
  align-items: center;
}

.config-dialog .strapping-row--head {
  font-size: 11px;
  font-weight: 600;
  color: #666;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  padding: 0 4px 4px;
  border-bottom: 1px solid #e6e8eb;
}

.config-dialog .strapping-col {
  text-align: left;
}

.config-dialog .strapping-input {
  width: 100%;
  padding: 6px 8px;
  border: 1px solid #d4d6d9;
  border-radius: 4px;
  font-size: 13px;
  background: #ffffff;
  box-sizing: border-box;
}

.config-dialog .strapping-input:focus {
  outline: none;
  border-color: #ee7623;
  box-shadow: 0 0 0 2px rgba(238, 118, 35, 0.15);
}

.config-dialog .strapping-remove {
  width: 32px !important;
  height: 32px !important;
  line-height: 32px !important;
  color: #b0b3b6 !important;
}

.config-dialog .strapping-remove:hover {
  color: #f44336 !important;
}

.config-dialog .strapping-remove .mat-icon {
  font-size: 18px;
  width: 18px;
  height: 18px;
}

.config-dialog .strapping-empty {
  padding: 12px;
  text-align: center;
  font-size: 12px;
  color: #999;
  font-style: italic;
}

.config-dialog .strapping-add {
  margin-top: 10px;
  color: #ee7623 !important;
  border-color: #ee7623 !important;
  text-transform: none;
  font-weight: 500;
}

.config-dialog .strapping-add .mat-icon {
  margin-right: 4px;
}

/* ── Actions ── */
.config-dialog .dialog-actions {
  padding: 12px 20px 16px;
  background: #ffffff;
  display: flex;
  justify-content: flex-end;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
  border-top: 1px solid #eee;
}

.config-dialog .dialog-actions .cancel-btn {
  color: #666 !important;
  font-weight: 400;
  text-transform: none;
  letter-spacing: 0.2px;
}

.config-dialog .dialog-actions .save-btn {
  background: #24272a !important;
  color: #ffffff !important;
  font-weight: 500;
  text-transform: none;
  letter-spacing: 0.3px;
  border-radius: 6px !important;
  padding: 0 20px !important;
  box-shadow: 0 2px 8px rgba(36, 39, 42, 0.3) !important;
  transition:
    box-shadow 0.2s ease,
    transform 0.15s ease !important;
}

.config-dialog .dialog-actions .save-btn:hover:not([disabled]) {
  box-shadow: 0 4px 12px rgba(36, 39, 42, 0.45) !important;
  transform: translateY(-1px);
}

.config-dialog .dialog-actions .save-btn[disabled] {
  opacity: 0.55;
}

actionCellButton.customFunction:
// ThingsBoard PE - Widget Configuración de Niveles (diálogo único)
// Para: Action cell button en tabla de dispositivos.
// Diálogo compartido para todos los devices que miden nivel.
// El comportamiento por tipo se define en LEVEL_PROFILES:
//   - gate:      "type"   -> habilita por device.type (radar EM410/EM411/UDL)
//                "system" -> habilita por server attr system === "level" (UC501/SWL)
//   - secondary: "depth"    -> métrica secundaria Profundidad (enable_depth / unit_depth)
//                "distance" -> métrica secundaria Distancia  (enable_distance / unit_distance)
//                "none"     -> sin métrica secundaria
// Forma de tanque unificada en v_composite (legacy v_cylinder_cone se migra al cargar).
// Todo se guarda en SERVER_SCOPE. Los downlinks viven en la acción "Configuración avanzada".

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get("customDialog"));
let deviceService = $injector.get(
  widgetContext.servicesMap.get("deviceService"),
);
let attributeService = $injector.get(
  widgetContext.servicesMap.get("attributeService"),
);

const LEVEL_PROFILES = {
  "EM410-RDL": { gate: "type", secondary: "depth" },
  "EM411-RDL": { gate: "type", secondary: "depth" },
  "EM410-RDL-TEST": { gate: "type", secondary: "depth" },
  "UC501": { gate: "system", secondary: "distance" },
  // Preparados — activar en showHide.js y validar contra su CF antes de usar:
  // "EM500-UDL": { gate: "type",   secondary: "depth" },
  // "EM500-SWL": { gate: "system", secondary: "none", metrics: ["level"] },
};

const SECONDARY_META = {
  depth: {
    label: "Profundidad",
    desc: "Altura de líquido desde el fondo",
    unitLabel: "Unidad de profundidad",
    attrEnable: "enable_depth",
    attrUnit: "unit_depth",
    metricKey: "depth",
  },
  distance: {
    label: "Distancia",
    desc: "Distancia medida del sensor al líquido",
    unitLabel: "Unidad de distancia",
    attrEnable: "enable_distance",
    attrUnit: "unit_distance",
    metricKey: "distance",
  },
};

openConfigLevelsDialog();

function openConfigLevelsDialog() {
  customDialog.customDialog(htmlTemplate, ConfigLevelsController).subscribe();
}

function ConfigLevelsController(instance) {
  let vm = instance;

  let deviceId = entityId.id;
  vm.loading = true;
  vm.saving = false;
  vm.device = null;
  vm.deviceType = null;
  vm.isLevel = false;
  vm.unsupported = false;
  vm.profile = null;
  vm.secondary = null;
  vm.hasSecondary = false;
  vm.secondaryLabel = "";
  vm.secondaryDesc = "";
  vm.secondaryUnitLabel = "";

  vm.volumeUnitOptions = [
    { value: "L", label: "Litros" },
    { value: "m3", label: "Metros cúbicos (m³)" },
  ];
  vm.tankTypeOptions = [
    { value: "linear", label: "Lineal (volumen máximo)" },
    { value: "rectangular", label: "Rectangular (caja plana)" },
    { value: "h_cylinder", label: "Cilíndrico horizontal" },
    { value: "v_composite", label: "Cilíndrico vertical (cono / casquete)" },
    { value: "strapping", label: "Tabla de calibración" },
  ];
  vm.bottomShapeOptions = [
    { value: "none", label: "Plano (sin fondo)" },
    { value: "cone", label: "Cónico" },
    { value: "sphere_cap", label: "Casquete esférico" },
  ];
  vm.topShapeOptions = [
    { value: "none", label: "Plano (sin tapa)" },
    { value: "sphere_cap", label: "Casquete esférico" },
  ];

  vm.configFormGroup = vm.fb.group({
    distanceMin: [null],
    distanceMax: [null],
    enableLevel: [true],
    enableSecondary: [false],
    secondaryUnit: ["m"],
    enableVolume: [false],
    volumeUnit: ["L"],
    tankType: [null],
    tankDiameter: [null],
    tankLength: [null],
    tankWidth: [null],
    tankRectLength: [null],
    tankBottomShape: ["none"],
    tankBottomHeight: [null],
    tankTopShape: ["none"],
    tankTopHeight: [null],
    tankCapacity: [null],
  });

  vm.CAPACITY_TOLERANCE = 0.10;

  vm.strappingRows = [];

  let originalDistanceMin = null;
  let originalDistanceMax = null;
  let originalEnabledMetrics = null;

  function validateMinMax() {
    let minCtrl = vm.configFormGroup.get("distanceMin");
    let maxCtrl = vm.configFormGroup.get("distanceMax");
    let min = minCtrl.value;
    let max = maxCtrl.value;
    if (min == null || max == null || min === "" || max === "") {
      minCtrl.setErrors(null);
      return;
    }
    if (parseFloat(min) <= parseFloat(max)) {
      minCtrl.setErrors({ minNotGreater: true });
    } else {
      minCtrl.setErrors(null);
    }
  }

  vm.configFormGroup.get("distanceMin").valueChanges.subscribe(function () {
    validateMinMax();
    validateTankFit();
    validateCapacityFit();
  });
  vm.configFormGroup.get("distanceMax").valueChanges.subscribe(function () {
    validateMinMax();
    validateTankFit();
    validateCapacityFit();
  });
  vm.configFormGroup.get("tankDiameter").valueChanges.subscribe(function () {
    validateTankFit();
    validateCapacityFit();
  });
  vm.configFormGroup.get("tankType").valueChanges.subscribe(function () {
    validateTankFit();
    validateCapacityFit();
  });
  vm.configFormGroup.get("tankLength").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("tankWidth").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("tankRectLength").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("tankBottomShape").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("tankBottomHeight").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("tankTopShape").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("tankTopHeight").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("tankCapacity").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("volumeUnit").valueChanges.subscribe(validateCapacityFit);
  vm.configFormGroup.get("enableVolume").valueChanges.subscribe(validateCapacityFit);

  // Volumen lleno de un casquete esférico (radio base r, altura h).
  function sphCapFullVol(r, h) {
    if (!(h > 0)) return 0;
    let R = (r * r + h * h) / (2 * h);
    return Math.PI * h * h * (R - h / 3);
  }

  function capFullVolM3(shape, r, h) {
    if (shape === "cone") return (Math.PI / 3) * r * r * h;
    if (shape === "sphere_cap") return sphCapFullVol(r, h);
    return 0;
  }

  function computeGeomCapacityM3() {
    let f = vm.configFormGroup.value;
    if (!f.tankType) return null;
    let dMin = parseFloat(f.distanceMin);
    let dMax = parseFloat(f.distanceMax);

    if (f.tankType === "rectangular") {
      let W = parseFloat(f.tankWidth);
      let L = parseFloat(f.tankRectLength);
      if (isNaN(W) || isNaN(L) || isNaN(dMin) || isNaN(dMax) || dMin <= dMax) return null;
      return W * L * (dMin - dMax);
    }
    if (f.tankType === "h_cylinder") {
      let D = parseFloat(f.tankDiameter);
      let L = parseFloat(f.tankLength);
      if (isNaN(D) || isNaN(L)) return null;
      return Math.PI * (D / 2) * (D / 2) * L;
    }
    if (f.tankType === "v_composite") {
      let D = parseFloat(f.tankDiameter);
      if (isNaN(D) || isNaN(dMin) || isNaN(dMax) || dMin <= dMax) return null;
      let r = D / 2;
      let h_cyl = dMin - dMax;
      let bH = parseFloat(f.tankBottomHeight);
      let tH = parseFloat(f.tankTopHeight);
      let vBot = (f.tankBottomShape && f.tankBottomShape !== "none" && !isNaN(bH))
        ? capFullVolM3(f.tankBottomShape, r, bH) : 0;
      let vTop = (f.tankTopShape && f.tankTopShape !== "none" && !isNaN(tH))
        ? capFullVolM3(f.tankTopShape, r, tH) : 0;
      return vBot + Math.PI * r * r * h_cyl + vTop;
    }
    if (f.tankType === "strapping") {
      if (vm.strappingRows.length === 0) return null;
      let last = vm.strappingRows[vm.strappingRows.length - 1];
      if (last.v == null || last.v === "") return null;
      return parseFloat(last.v) / 1000.0;
    }
    return null;
  }

  function validateCapacityFit() {
    vm.capacityWarning = null;
    let f = vm.configFormGroup.value;
    if (!f.enableVolume) return;
    if (f.tankType === "linear") return;
    let cap = parseFloat(f.tankCapacity);
    if (isNaN(cap)) return;
    let geom_m3 = computeGeomCapacityM3();
    if (geom_m3 == null) return;
    let geom = (f.volumeUnit === "m3") ? geom_m3 : geom_m3 * 1000;
    let diff = Math.abs(geom - cap) / geom;
    if (diff > vm.CAPACITY_TOLERANCE) {
      vm.capacityWarning = {
        computed: geom,
        entered: cap,
        diffPct: diff * 100,
      };
    }
  }

  function deriveCapacityFromTank(tank, unit, dMin, dMax) {
    if (!tank || !tank.type) return null;
    let cap_m3 = null;
    if (tank.type === "linear") {
      if (tank.volume_max == null) return null;
      cap_m3 = tank.volume_max / 1000.0;
    } else if (tank.type === "rectangular") {
      if (tank.width == null || tank.length == null || dMin == null || dMax == null) return null;
      let h_total = parseFloat(dMin) - parseFloat(dMax);
      if (h_total <= 0) return null;
      cap_m3 = parseFloat(tank.width) * parseFloat(tank.length) * h_total;
    } else if (tank.type === "h_cylinder") {
      if (tank.diameter == null || tank.length == null) return null;
      cap_m3 = Math.PI * (tank.diameter / 2) * (tank.diameter / 2) * tank.length;
    } else if (tank.type === "v_cylinder_cone") {
      if (tank.diameter == null || tank.cone_height == null || dMin == null || dMax == null) return null;
      let r = tank.diameter / 2;
      let h_total = parseFloat(dMin) - parseFloat(dMax);
      if (h_total <= 0) return null;
      cap_m3 = (Math.PI / 3) * r * r * tank.cone_height + Math.PI * r * r * h_total;
    } else if (tank.type === "v_composite") {
      if (tank.diameter == null || dMin == null || dMax == null) return null;
      let r = tank.diameter / 2;
      let h_total = parseFloat(dMin) - parseFloat(dMax);
      if (h_total <= 0) return null;
      let vBot = (tank.bottom && tank.bottom.shape && tank.bottom.shape !== "none")
        ? capFullVolM3(tank.bottom.shape, r, tank.bottom.height) : 0;
      let vTop = (tank.top && tank.top.shape && tank.top.shape !== "none")
        ? capFullVolM3(tank.top.shape, r, tank.top.height) : 0;
      cap_m3 = vBot + Math.PI * r * r * h_total + vTop;
    } else if (tank.type === "strapping") {
      if (!Array.isArray(tank.table) || tank.table.length === 0) return null;
      let lastV = tank.table[tank.table.length - 1][1];
      cap_m3 = lastV / 1000.0;
    }
    if (cap_m3 == null) return null;
    return (unit === "m3") ? cap_m3 : cap_m3 * 1000;
  }

  function validateTankFit() {
    let ctrl = vm.configFormGroup.get("tankDiameter");
    let type = vm.configFormGroup.get("tankType").value;
    if (type !== "h_cylinder") {
      ctrl.setErrors(null);
      return;
    }
    let D = vm.configFormGroup.get("tankDiameter").value;
    let dMin = vm.configFormGroup.get("distanceMin").value;
    let dMax = vm.configFormGroup.get("distanceMax").value;
    if (D == null || D === "" || dMin == null || dMin === "" || dMax == null || dMax === "") {
      ctrl.setErrors(null);
      return;
    }
    let hTotal = parseFloat(dMin) - parseFloat(dMax);
    if (hTotal < parseFloat(D)) {
      ctrl.setErrors({ cylinderTooTall: true });
    } else {
      ctrl.setErrors(null);
    }
  }

  vm.addStrappingRow = function () {
    vm.strappingRows.push({ h: null, v: null });
    validateCapacityFit();
  };

  vm.removeStrappingRow = function (idx) {
    vm.strappingRows.splice(idx, 1);
    validateCapacityFit();
  };

  vm.onStrappingRowChange = function () {
    validateCapacityFit();
  };

  vm.strappingValid = function () {
    if (vm.strappingRows.length < 2) return false;
    let prevH = -Infinity;
    for (let i = 0; i < vm.strappingRows.length; i++) {
      let r = vm.strappingRows[i];
      if (r.h == null || r.h === "" || r.v == null || r.v === "") return false;
      let h = parseFloat(r.h);
      let v = parseFloat(r.v);
      if (isNaN(h) || isNaN(v) || v < 0) return false;
      if (h <= prevH) return false;
      prevH = h;
    }
    return true;
  };

  vm.anyMetricOn = function () {
    let f = vm.configFormGroup.value;
    return !!(f.enableLevel || (vm.hasSecondary && f.enableSecondary) || f.enableVolume);
  };

  vm.computedCapacity = function () {
    let geom_m3 = computeGeomCapacityM3();
    if (geom_m3 == null) return null;
    let unit = vm.configFormGroup.get("volumeUnit").value;
    return (unit === "m3") ? geom_m3 : geom_m3 * 1000;
  };

  vm.formInvalid = function () {
    if (vm.configFormGroup.invalid) return true;
    let f = vm.configFormGroup.value;
    if (!vm.anyMetricOn()) return false;
    if (f.distanceMin == null || f.distanceMin === "") return true;
    if (f.distanceMax == null || f.distanceMax === "") return true;
    if (!f.tankType) return true;

    // composite: alturas de los apéndices se necesitan también para level/secundaria
    if (f.tankType === "v_composite") {
      if (f.tankBottomShape && f.tankBottomShape !== "none" &&
          (f.tankBottomHeight == null || f.tankBottomHeight === "")) return true;
      if (f.tankTopShape && f.tankTopShape !== "none" &&
          (f.tankTopHeight == null || f.tankTopHeight === "")) return true;
    }

    if (!f.enableVolume) return false;
    if (f.tankCapacity == null || f.tankCapacity === "") return true;
    if (f.tankType === "h_cylinder" &&
        ((f.tankDiameter == null || f.tankDiameter === "") ||
         (f.tankLength == null || f.tankLength === ""))) return true;
    if (f.tankType === "rectangular" && f.enableVolume &&
        ((f.tankWidth == null || f.tankWidth === "") ||
         (f.tankRectLength == null || f.tankRectLength === ""))) return true;
    if (f.tankType === "v_composite" &&
        (f.tankDiameter == null || f.tankDiameter === "")) return true;
    if (f.tankType === "strapping" && !vm.strappingValid()) return true;
    return false;
  };

  vm.cancel = function () {
    vm.dialogRef.close(null);
  };

  vm.save = function () {
    if (vm.formInvalid()) return;
    vm.saving = true;

    let entity = { id: deviceId, entityType: "DEVICE" };
    let formValue = vm.configFormGroup.value;

    function finish() {
      vm.saving = false;
      widgetContext.showSuccessToast("Configuración actualizada");
      vm.dialogRef.close(true);
    }

    function fail(msg) {
      return function (error) {
        vm.saving = false;
        widgetContext.showErrorToast(
          msg + ": " + (error.message || JSON.stringify(error)),
        );
      };
    }

    let serverAttrs = [];
    if (formValue.distanceMin != null && formValue.distanceMin !== "") {
      serverAttrs.push({ key: "distance_min", value: parseFloat(formValue.distanceMin) });
    }
    if (formValue.distanceMax != null && formValue.distanceMax !== "") {
      serverAttrs.push({ key: "distance_max", value: parseFloat(formValue.distanceMax) });
    }

    serverAttrs.push({ key: "enable_level", value: !!formValue.enableLevel });
    serverAttrs.push({ key: "enable_volume", value: !!formValue.enableVolume });

    if (vm.hasSecondary) {
      serverAttrs.push({ key: vm.secondary.attrEnable, value: !!formValue.enableSecondary });
      if (formValue.enableSecondary) {
        serverAttrs.push({ key: vm.secondary.attrUnit, value: formValue.secondaryUnit || "m" });
      }
    }

    if (formValue.tankType) {
      serverAttrs.push({ key: "tank_type", value: formValue.tankType });
    }

    if (formValue.enableVolume) {
      let unit = formValue.volumeUnit || "L";
      let cap = parseFloat(formValue.tankCapacity);
      serverAttrs.push({ key: "unit_volume", value: unit });
      serverAttrs.push({ key: "volume_max", value: cap });
    }

    if (vm.anyMetricOn()) {
      let tank = {};
      if (formValue.tankType) {
        tank.type = formValue.tankType;
        if (formValue.tankType === "h_cylinder") {
          if (formValue.tankDiameter != null && formValue.tankDiameter !== "") {
            tank.diameter = parseFloat(formValue.tankDiameter);
          }
          if (formValue.tankLength != null && formValue.tankLength !== "") {
            tank.length = parseFloat(formValue.tankLength);
          }
        } else if (formValue.tankType === "v_composite") {
          if (formValue.tankDiameter != null && formValue.tankDiameter !== "") {
            tank.diameter = parseFloat(formValue.tankDiameter);
          }
          let bShape = formValue.tankBottomShape || "none";
          tank.bottom = { shape: bShape };
          if (bShape !== "none" && formValue.tankBottomHeight != null && formValue.tankBottomHeight !== "") {
            tank.bottom.height = parseFloat(formValue.tankBottomHeight);
          }
          let tShape = formValue.tankTopShape || "none";
          tank.top = { shape: tShape };
          if (tShape !== "none" && formValue.tankTopHeight != null && formValue.tankTopHeight !== "") {
            tank.top.height = parseFloat(formValue.tankTopHeight);
          }
        } else if (formValue.tankType === "rectangular") {
          if (formValue.tankWidth != null && formValue.tankWidth !== "") {
            tank.width = parseFloat(formValue.tankWidth);
          }
          if (formValue.tankRectLength != null && formValue.tankRectLength !== "") {
            tank.length = parseFloat(formValue.tankRectLength);
          }
        } else if (formValue.tankType === "strapping" && vm.strappingRows.length > 0) {
          tank.table = vm.strappingRows.map(function (r) {
            return [parseFloat(r.h), parseFloat(r.v)];
          });
        }
        if (formValue.enableVolume) {
          let cap2 = parseFloat(formValue.tankCapacity);
          let cap_l = (formValue.volumeUnit === "m3") ? cap2 * 1000 : cap2;
          tank.volume_max = cap_l;
        }
      }
      serverAttrs.push({ key: "tank_config", value: JSON.stringify(tank) });
    }

    attributeService
      .saveEntityAttributes(entity, "SERVER_SCOPE", serverAttrs)
      .subscribe(finish, fail("Error guardando configuración"));
  };

  loadDevice();

  function loadDevice() {
    deviceService.getDevice(deviceId).subscribe(
      function (device) {
        vm.device = device;
        vm.deviceType = device.type;
        vm.profile = LEVEL_PROFILES[device.type] || null;
        if (!vm.profile) {
          vm.unsupported = true;
          vm.loading = false;
          return;
        }
        vm.secondary = vm.profile.secondary && vm.profile.secondary !== "none"
          ? SECONDARY_META[vm.profile.secondary] : null;
        vm.hasSecondary = !!vm.secondary;
        if (vm.secondary) {
          vm.secondaryLabel = vm.secondary.label;
          vm.secondaryDesc = vm.secondary.desc;
          vm.secondaryUnitLabel = vm.secondary.unitLabel;
        }
        loadLevelAttrs();
      },
      function (error) {
        vm.loading = false;
        widgetContext.showErrorToast("Error cargando dispositivo");
        console.error("Error cargando dispositivo:", error);
      },
    );
  }

  function loadLevelAttrs() {
    let entity = { id: deviceId, entityType: "DEVICE" };
    let serverKeys = [
      "system",
      "distance_min", "distance_max",
      "enable_level", "enable_depth", "unit_depth",
      "enable_distance", "unit_distance",
      "enable_volume", "unit_volume", "tank_type", "volume_max", "tank_config",
      "enabled_metrics", "volume_unit",
    ];

    attributeService.getEntityAttributes(entity, "SERVER_SCOPE", serverKeys).subscribe(
      function (serverAttrs) {
        let systemVal = null;
        let flat = {
          hasFlag: false,
          enableLevel: null,
          enableDepth: null,
          enableDistance: null,
          enableVolume: null,
          unitDepth: null,
          unitDistance: null,
          unitVolume: null,
          tankType: null,
          volumeMax: null,
        };
        let tankConfigRaw = null;
        let enabledMetricsRaw = null;
        let legacyVolumeUnit = null;
        let pendingDistanceMin = null;
        let pendingDistanceMax = null;

        if (serverAttrs) {
          serverAttrs.forEach(function (a) {
            if (a.key === "system") {
              systemVal = a.value;
            } else if (a.key === "distance_min") {
              pendingDistanceMin = a.value;
            } else if (a.key === "distance_max") {
              pendingDistanceMax = a.value;
            } else if (a.key === "enable_level") {
              flat.hasFlag = true; flat.enableLevel = !!a.value;
            } else if (a.key === "enable_depth") {
              flat.hasFlag = true; flat.enableDepth = !!a.value;
            } else if (a.key === "enable_distance") {
              flat.hasFlag = true; flat.enableDistance = !!a.value;
            } else if (a.key === "enable_volume") {
              flat.hasFlag = true; flat.enableVolume = !!a.value;
            } else if (a.key === "unit_depth") {
              flat.unitDepth = a.value;
            } else if (a.key === "unit_distance") {
              flat.unitDistance = a.value;
            } else if (a.key === "unit_volume") {
              flat.unitVolume = a.value;
            } else if (a.key === "tank_type") {
              flat.tankType = a.value;
            } else if (a.key === "volume_max") {
              flat.volumeMax = a.value;
            } else if (a.key === "tank_config") {
              tankConfigRaw = a.value;
            } else if (a.key === "enabled_metrics") {
              enabledMetricsRaw = a.value;
              originalEnabledMetrics = a.value;
            } else if (a.key === "volume_unit") {
              legacyVolumeUnit = a.value;
            }
          });
        }

        // Gate
        if (vm.profile.gate === "system" && systemVal !== "level") {
          vm.unsupported = true;
          vm.loading = false;
          return;
        }

        vm.isLevel = true;

        if (pendingDistanceMin != null) {
          originalDistanceMin = pendingDistanceMin;
          vm.configFormGroup.patchValue({ distanceMin: pendingDistanceMin });
        }
        if (pendingDistanceMax != null) {
          originalDistanceMax = pendingDistanceMax;
          vm.configFormGroup.patchValue({ distanceMax: pendingDistanceMax });
        }

        if (flat.hasFlag) {
          applyFlatAttrs(flat, tankConfigRaw);
        } else if (enabledMetricsRaw != null) {
          applyEnabledMetrics(enabledMetricsRaw);
        } else if (tankConfigRaw != null) {
          applyLegacyTankConfig(tankConfigRaw, legacyVolumeUnit);
        }
        vm.loading = false;
      },
      function () { vm.loading = false; },
    );
  }

  function applyFlatAttrs(flat, tankConfigRaw) {
    vm.configFormGroup.patchValue({
      enableLevel: !!flat.enableLevel,
      enableVolume: !!flat.enableVolume,
    });
    if (vm.hasSecondary) {
      let enabled = vm.profile.secondary === "depth" ? flat.enableDepth : flat.enableDistance;
      let unit = vm.profile.secondary === "depth" ? flat.unitDepth : flat.unitDistance;
      vm.configFormGroup.patchValue({ enableSecondary: !!enabled });
      if (unit) {
        vm.configFormGroup.patchValue({ secondaryUnit: unit });
      }
    }
    if (flat.unitVolume) {
      vm.configFormGroup.patchValue({ volumeUnit: flat.unitVolume });
    }
    if (flat.volumeMax != null) {
      vm.configFormGroup.patchValue({ tankCapacity: flat.volumeMax });
    }
    if (tankConfigRaw != null) {
      let cfg;
      try {
        cfg = typeof tankConfigRaw === "string" ? JSON.parse(tankConfigRaw) : tankConfigRaw;
      } catch (e) {
        console.error("tank_config inválido:", e);
        cfg = null;
      }
      if (cfg) {
        applyTankShape(cfg);
      } else if (flat.tankType) {
        vm.configFormGroup.patchValue({ tankType: migrateTankType(flat.tankType) });
      }
    } else if (flat.tankType) {
      vm.configFormGroup.patchValue({ tankType: migrateTankType(flat.tankType) });
    }
  }

  function applyEnabledMetrics(raw) {
    let cfg;
    try {
      cfg = typeof raw === "string" ? JSON.parse(raw) : raw;
    } catch (e) {
      console.error("enabled_metrics inválido:", e);
      return;
    }
    if (!cfg || typeof cfg !== "object") return;

    vm.configFormGroup.patchValue({
      enableLevel: cfg.level != null,
      enableVolume: cfg.volume != null,
    });

    if (vm.hasSecondary) {
      let key = vm.secondary.metricKey;
      vm.configFormGroup.patchValue({ enableSecondary: cfg[key] != null });
      if (cfg[key] && cfg[key].unit) {
        vm.configFormGroup.patchValue({ secondaryUnit: cfg[key].unit });
      }
    }

    if (cfg.volume) {
      let unit = cfg.volume.unit || "L";
      if (cfg.volume.unit) {
        vm.configFormGroup.patchValue({ volumeUnit: cfg.volume.unit });
      }
      if (cfg.volume.tank) {
        applyTankShape(cfg.volume.tank);
        prefillCapacity(cfg.volume.tank, unit);
      }
    }
  }

  function applyLegacyTankConfig(raw, legacyUnit) {
    let cfg;
    try {
      cfg = typeof raw === "string" ? JSON.parse(raw) : raw;
    } catch (e) {
      console.error("tank_config inválido:", e);
      return;
    }
    if (!cfg || !cfg.type) return;
    let unit = legacyUnit || "L";
    vm.configFormGroup.patchValue({
      enableLevel: true,
      enableVolume: true,
      volumeUnit: unit,
    });
    applyTankShape(cfg);
    prefillCapacity(cfg, unit);
  }

  function migrateTankType(t) {
    return (t === "v_cylinder_cone") ? "v_composite" : t;
  }

  function applyTankShape(tank) {
    if (!tank || !tank.type) return;
    if (tank.type === "h_cylinder") {
      vm.configFormGroup.patchValue({
        tankType: "h_cylinder",
        tankDiameter: tank.diameter,
        tankLength: tank.length,
      });
    } else if (tank.type === "v_cylinder_cone") {
      // Migración: cono viejo -> composite con fondo cónico, tapa plana
      vm.configFormGroup.patchValue({
        tankType: "v_composite",
        tankDiameter: tank.diameter,
        tankBottomShape: "cone",
        tankBottomHeight: tank.cone_height,
        tankTopShape: "none",
        tankTopHeight: null,
      });
    } else if (tank.type === "v_composite") {
      let b = tank.bottom || { shape: "none" };
      let t = tank.top || { shape: "none" };
      vm.configFormGroup.patchValue({
        tankType: "v_composite",
        tankDiameter: tank.diameter,
        tankBottomShape: b.shape || "none",
        tankBottomHeight: b.height != null ? b.height : null,
        tankTopShape: t.shape || "none",
        tankTopHeight: t.height != null ? t.height : null,
      });
    } else if (tank.type === "rectangular") {
      vm.configFormGroup.patchValue({
        tankType: "rectangular",
        tankWidth: tank.width,
        tankRectLength: tank.length,
      });
    } else if (tank.type === "strapping" && Array.isArray(tank.table)) {
      vm.configFormGroup.patchValue({ tankType: "strapping" });
      vm.strappingRows = tank.table.map(function (pair) {
        return { h: pair[0], v: pair[1] };
      });
    } else {
      vm.configFormGroup.patchValue({ tankType: tank.type });
    }
  }

  function prefillCapacity(tank, unit) {
    let cap = deriveCapacityFromTank(
      tank, unit,
      vm.configFormGroup.get("distanceMin").value,
      vm.configFormGroup.get("distanceMax").value,
    );
    if (cap != null) {
      vm.configFormGroup.patchValue({ tankCapacity: cap });
    }
  }
}

