actionCellButton.customFunction:
// ThingsBoard PE - Widget Configuración EM300-MCS (interpretación de magnet_status)
// Para: Action cell button en tabla de dispositivos.
// El EM300-MCS reporta magnet_status (open/close). Este diálogo define cómo
// interpretarlo, guardándolo en el server attr objeto `mcs_config`:
//   {
//     application: "door" | "motor" | "custom",
//     contact:     "NA" | "NC",
//     labels:      { active: "...", inactive: "..." }
//   }
// Mapeo base: NC -> close=inactivo, open=activo. NA invierte.
// La interpretación a label la hacen los widgets/CF que leen mcs_config.
// La activación de la alarma se hace por separado desde el dashboard de
// administración de alarmas (server attr `magnet_alarm_when`).

let $injector = widgetContext.$scope.$injector;
let customDialog = $injector.get(widgetContext.servicesMap.get("customDialog"));
let deviceService = $injector.get(
  widgetContext.servicesMap.get("deviceService"),
);
let attributeService = $injector.get(
  widgetContext.servicesMap.get("attributeService"),
);

const MCS_TYPES = ["EM300-MCS"];

const DEFAULT_LABELS = {
  door: { active: "Abierta", inactive: "Cerrada" },
  motor: { active: "Marcha", inactive: "Paro" },
  custom: { active: "Activo", inactive: "Inactivo" },
};

openConfigMcsDialog();

function openConfigMcsDialog() {
  customDialog.customDialog(htmlTemplate, ConfigMcsController).subscribe();
}

function ConfigMcsController(instance) {
  let vm = instance;

  let deviceId = entityId.id;
  vm.loading = true;
  vm.saving = false;
  vm.device = null;
  vm.deviceType = null;
  vm.unsupported = false;

  vm.applicationOptions = [
    { value: "door", label: "Puerta" },
    { value: "motor", label: "Motor" },
    { value: "custom", label: "Otro (personalizado)" },
  ];
  vm.contactOptions = [
    { value: "NC", label: "NC — Normalmente cerrado" },
    { value: "NA", label: "NA — Normalmente abierto" },
  ];
  vm.configFormGroup = vm.fb.group({
    application: ["door"],
    contact: ["NC"],
    labelActive: ["Abierta"],
    labelInactive: ["Cerrada"],
  });

  vm._loaded = false;

  vm.isCustom = function () {
    return vm.configFormGroup.get("application").value === "custom";
  };

  vm.hasContactWiring = function () {
    // Puerta: usa imán incorporado → NC fijo, sin elección de cableado.
    return vm.configFormGroup.get("application").value !== "door";
  };

  // Al cambiar la aplicación (después de cargar), aplicar labels por defecto.
  // Para puerta además forzamos contact = NC (no se cablea).
  vm.configFormGroup.get("application").valueChanges.subscribe(function (app) {
    if (!vm._loaded) return;
    let def = DEFAULT_LABELS[app] || DEFAULT_LABELS.custom;
    let patch = {
      labelActive: def.active,
      labelInactive: def.inactive,
    };
    if (app === "door") patch.contact = "NC";
    vm.configFormGroup.patchValue(patch);
  });

  // Estado lógico de cada valor de magnet_status según contact.
  // NC: close=inactivo, open=activo.  NA: invierte.
  function isActive(magnetValue) {
    let contact = vm.configFormGroup.get("contact").value;
    if (contact === "NA") return magnetValue === "close";
    return magnetValue === "open";
  }

  vm.labelFor = function (magnetValue) {
    let f = vm.configFormGroup.value;
    return isActive(magnetValue) ? f.labelActive : f.labelInactive;
  };

  vm.isActiveValue = function (magnetValue) {
    return isActive(magnetValue);
  };

  vm.formInvalid = function () {
    let f = vm.configFormGroup.value;
    if (!f.application || !f.contact) return true;
    if (f.labelActive == null || f.labelActive === "") return true;
    if (f.labelInactive == null || f.labelInactive === "") return true;
    return false;
  };

  vm.cancel = function () {
    vm.dialogRef.close(null);
  };

  vm.save = function () {
    if (vm.formInvalid()) return;
    vm.saving = true;

    let entity = { id: deviceId, entityType: "DEVICE" };
    let f = vm.configFormGroup.value;
    let cfg = {
      application: f.application,
      contact: f.contact,
      labels: {
        active: f.labelActive,
        inactive: f.labelInactive,
      },
    };

    attributeService
      .saveEntityAttributes(entity, "SERVER_SCOPE", [{ key: "mcs_config", value: cfg }])
      .subscribe(
        function () {
          vm.saving = false;
          widgetContext.showSuccessToast("Configuración actualizada");
          vm.dialogRef.close(true);
        },
        function (error) {
          vm.saving = false;
          widgetContext.showErrorToast(
            "Error guardando configuración: " + (error.message || JSON.stringify(error)),
          );
        },
      );
  };

  loadDevice();

  function loadDevice() {
    deviceService.getDevice(deviceId).subscribe(
      function (device) {
        vm.device = device;
        vm.deviceType = device.type;
        if (MCS_TYPES.indexOf(device.type) === -1) {
          vm.unsupported = true;
          vm.loading = false;
          return;
        }
        loadMcsConfig();
      },
      function (error) {
        vm.loading = false;
        widgetContext.showErrorToast("Error cargando dispositivo");
        console.error("Error cargando dispositivo:", error);
      },
    );
  }

  function loadMcsConfig() {
    let entity = { id: deviceId, entityType: "DEVICE" };
    attributeService.getEntityAttributes(entity, "SERVER_SCOPE", ["mcs_config"]).subscribe(
      function (attrs) {
        let cfg = null;
        if (attrs) {
          attrs.forEach(function (a) {
            if (a.key === "mcs_config") {
              try {
                cfg = typeof a.value === "string" ? JSON.parse(a.value) : a.value;
              } catch (e) {
                console.error("mcs_config inválido:", e);
              }
            }
          });
        }
        if (cfg && typeof cfg === "object") {
          let app = cfg.application || "door";
          let def = DEFAULT_LABELS[app] || DEFAULT_LABELS.custom;
          let labels = cfg.labels || {};
          let contact = app === "door" ? "NC" : (cfg.contact === "NA" ? "NA" : "NC");
          vm.configFormGroup.patchValue({
            application: app,
            contact: contact,
            labelActive: labels.active != null ? labels.active : def.active,
            labelInactive: labels.inactive != null ? labels.inactive : def.inactive,
          });
        }
        vm._loaded = true;
        vm.loading = false;
      },
      function () {
        vm._loaded = true;
        vm.loading = false;
      },
    );
  }
}
